import React, { useState } from 'react';
import axios from 'axios';

const LeadDetail = ({ lead, fetchLeads, onClose }) => {
  const [status, setStatus] = useState(lead.status);
  const [note, setNote] = useState('');

  const handleStatusChange = async () => {
    try {
      await axios.put(`http://localhost:5000/api/leads/${lead._id}`, { status });
      fetchLeads();
    } catch (err) {
      console.error(err);
    }
  };

  const handleAddNote = async () => {
    if (!note.trim()) return;
    try {
      await axios.post(`http://localhost:5000/api/leads/${lead._id}/notes`, { text: note });
      setNote('');
      fetchLeads();
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="lead-detail">
      <h2>{lead.name}</h2>
      <p>Email: {lead.email}</p>
      <p>Phone: {lead.phone || 'N/A'}</p>
      <p>Source: {lead.source}</p>
      <p>Status: 
        <select value={status} onChange={(e) => setStatus(e.target.value)}>
          <option value="new">New</option>
          <option value="contacted">Contacted</option>
          <option value="converted">Converted</option>
        </select>
        <button onClick={handleStatusChange}>Update Status</button>
      </p>
      <div className="notes">
        <h3>Notes</h3>
        <ul>
          {lead.notes.map((n, index) => (
            <li key={index}>{n.text} - {new Date(n.date).toLocaleDateString()}</li>
          ))}
        </ul>
        <textarea
          value={note}
          onChange={(e) => setNote(e.target.value)}
          placeholder="Add a note"
        />
        <button onClick={handleAddNote}>Add Note</button>
      </div>
    </div>
  );
};

export default LeadDetail;
